def normalize_plate(plate: str) -> str:
    """袩褉懈胁芯写懈屑 薪芯屑械褉 泻 械写懈薪芯屑褍 褎芯褉屑邪褌褍: 斜褍泻胁褘 蟹邪谐谢邪胁薪褘械, 褍写邪谢褟械屑 锌褉芯斜械谢褘."""
    return plate.upper().replace(" ", "").replace("-", "")

def is_valid_plate(plate: str) -> bool:
    """袩褉芯胁械褉褟械屑, 械褋褌褜 谢懈 薪芯屑械褉 (褋 褉械谐懈芯薪芯屑 懈谢懈 斜械蟹) 胁 褋锌懈褋泻械."""
    norm = normalize_plate(plate)
    # 小薪邪褔邪谢邪 褌芯褔薪芯械 褋芯胁锌邪写械薪懈械
    if norm in HARDCODED_PLATES:
        return True
    # 袩褘褌邪械屑褋褟 薪邪泄褌懈 斜械蟹 褉械谐懈芯薪邪 (锌芯褋谢械写薪懈械 3 褑懈褎褉褘)
    # 袝褋谢懈 薪芯屑械褉 写谢懈薪薪械械 6, 芯褌褉械蟹邪械屑 锌芯褋谢械写薪懈械 3 褋懈屑胁芯谢邪 (褉械谐懈芯薪)
    if len(norm) > 6:
        without_region = norm[:-3]
    else:
        without_region = norm
    # 袩褉芯胁械褉褟械屑, 械褋褌褜 谢懈 胁 褋锌懈褋泻械 薪芯屑械褉 褋 褌邪泻懈屑 芯褋薪芯胁邪薪懈械屑 懈 谢褞斜褘屑 褉械谐懈芯薪芯屑
    for valid in HARDCODED_PLATES:
        if valid.startswith(without_region) and len(valid) == len(without_region) + 3:
            return True
    return False

# --- 袨袘袪袗袘袨孝效袠袣袠 ---
async def start(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    await update.message.reply_text(
        "袙胁械写懈褌械 谐芯褋褍写邪褉褋褌胁械薪薪褘泄 薪芯屑械褉 胁邪褕械谐芯 邪胁褌芯屑芯斜懈谢褟 (薪邪锌褉懈屑械褉, 袗445袙袣797 懈谢懈 袗445袙袣):"
    )
    return PLATE

async def handle_plate(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    plate = update.message.text.strip()
    if not is_valid_plate(plate):
        await update.message.reply_text("校泻邪蟹邪薪 薪械胁械褉薪褘泄 薪芯屑械褉 孝小. 袩芯锌褉芯斜褍泄褌械 褋薪芯胁邪:")
        return PLATE
    context.user_data["plate"] = normalize_plate(plate)
    await update.message.reply_text(
        "袙胁械写懈褌械 胁邪褕 谐褉邪褎懈泻 褉邪斜芯褌褘 胁 褎芯褉屑邪褌械 效效:袦袦 - 效效:袦袦 (薪邪锌褉懈屑械褉, 16:00 - 00:00):"
    )
    return SCHEDULE

async def handle_schedule(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    schedule = update.message.text.strip()
    plate = context.user_data.get("plate", "薪械懈蟹胁械褋褌械薪")
    user = update.effective_user
    username = user.username if user.username else f"{user.first_name} {user.last_name or ''}"
    user_id = user.id

    msg = (
        f"袧芯胁芯械 芯斜褉邪褖械薪懈械 芯褌 胁芯写懈褌械谢褟:\n"
        f"ID: {user_id}\n"
        f"袠屑褟: {username}\n"
        f"袧芯屑械褉 孝小: {plate}\n"
        f"袚褉邪褎懈泻 褉邪斜芯褌褘: {schedule}\n"
        f"袙褉械屑褟 芯褌锌褉邪胁泻懈: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"
    )

    # 袨褌锌褉邪胁谢褟械屑 锌芯写褌胁械褉卸写械薪懈械 胁芯写懈褌械谢褞
    await update.message.reply_text(
        f"袙邪褕械 芯斜褉邪褖械薪懈械 锌褉懈薪褟褌芯. 袧芯屑械褉 孝小: {plate}, 谐褉邪褎懈泻: {schedule}."
    )

    # 袨褌锌褉邪胁谢褟械屑 写胁褍屑 邪写屑懈薪邪屑
    for admin_id in ADMIN_IDS:
        try:
            await context.bot.send_message(chat_id=admin_id, text=msg)
        except Exception as e:
            logger.error(f"袧械 褍写邪谢芯褋褜 芯褌锌褉邪胁懈褌褜 邪写屑懈薪褍 {admin_id}: {e}")

    return ConversationHandler.END

async def cancel(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    await update.message.reply_text("袨锌械褉邪褑懈褟 芯褌屑械薪械薪邪.")
    return ConversationHandler.END

async def error_handler(update: Update, context: ContextTypes.DEFAULT_TYPE) -> None:
    logger.warning(f"Update {update} caused error {context.error}")

# --- 袘袝袟校小蝎袩袥携袥袣袗 (keep-alive) ---
async def keep_alive():
    """肖芯薪芯胁褘泄 task, 褔褌芯斜褘 斜芯褌 薪械 蟹邪褋褘锌邪谢 薪邪 Render."""
    while True:
        await asyncio.sleep(150)  # 5 屑懈薪褍褌
        logger.info("Keep-alive ping")

async def post_init(application: Application) -> None:
    """袟邪锌褍褋泻邪械屑 keep-alive 锌芯褋谢械 懈薪懈褑懈邪谢懈蟹邪褑懈懈."""
    asyncio.create_task(keep_alive())

# --- MAIN ---
def main() -> None:
    application = Application.builder().token(TOKEN).post_init(post_init).build()

    conv_handler = ConversationHandler(
        entry_points=[CommandHandler("start", start)],
        states={
            PLATE: [MessageHandler(filters.TEXT & ~filters.COMMAND, handle_plate)],
            SCHEDULE: [MessageHandler(filters.TEXT & ~filters.COMMAND, handle_schedule)],
        },
        fallbacks=[CommandHandler("cancel", cancel)],
    )
    application.add_handler(conv_handler)
    application.add_error_handler(error_handler)

    # 袟邪锌褍褋泻
    application.run_polling(allowed_updates=Update.ALL_TYPES)

if __name__ == "__main__":
    main()
